"const fs = require('fs');
const path = require('path');

const searchDir = 'C:\\Users\\paulo';
const found = [];

function search(dir, depth = 0) {
  if (depth > 6) return;
  try {
    const files = fs.readdirSync(dir);
    for (const file of files) {
      const fullPath = path.join(dir, file);
      let stat;
      try {
        stat = fs.statSync(fullPath);
      } catch (e) {
        continue;
      }
      if (stat.isDirectory()) {
        const lowerName = file.toLowerCase();
        // Ignora pastas gigantescas ou irrelevantes
        if (
          lowerName !== 'node_modules' && 
          lowerName !== '.git' && 
          lowerName !== 'appdata' && 
          lowerName !== 'local' && 
          lowerName !== 'locallow' && 
          lowerName !== 'roaming' && 
          lowerName !== 'cache' && 
          lowerName !== 'dist' && 
          lowerName !== 'search' && 
          lowerName !== 'microsoft' && 
          lowerName !== 'windows'
        ) {
          search(fullPath, depth + 1);
        }
      } else if (file === 'CompanyDashboard.tsx') {
        found.push({ path: fullPath, size: stat.size, mtime: stat.mtime });
      }
    }
  } catch (e) {
    // Ignore errors
  }
}

search(searchDir);
console.log('Resultados encontrados em C:\\Users\\paulo:', JSON.stringify(found, null, 2));
"
